// Process and categorize emails
const results = [];

// Categories based on sender/domain/subject patterns
const categoryRules = {
  'alert': ['alert', 'warning', 'critical', 'error', 'down', 'incident'],
  'security': ['ssl', 'certificate', 'vulnerability', 'breach', 'unauthorized'],
  'billing': ['invoice', 'payment', 'billing', 'subscription', 'receipt'],
  'support': ['support', 'help', 'ticket', 'issue', 'bug', 'feedback'],
  'business': ['report', 'analytics', 'kpi', 'revenue', 'conversion', 'sales'],
  'system': ['deploy', 'restart', 'backup', 'update', 'upgrade', 'maintenance'],
  'marketing': ['campaign', 'newsletter', 'promotion', 'discount', 'offer']
};

function categorizeEmail(subject, sender) {
  const text = `${subject} ${sender}`.toLowerCase();

  for (const [category, keywords] of Object.entries(categoryRules)) {
    if (keywords.some(kw => text.includes(kw))) {
      return category;
    }
  }
  return 'other';
}

function estimatePriority(category, subject) {
  const text = subject.toLowerCase();
  let priority = 0.5; // neutral

  // Urgent keywords increase priority
  const urgent = ['urgent', 'critical', 'down', 'emergency', 'asap', 'immediately'];
  if (urgent.some(kw => text.includes(kw))) priority = 0.9;

  // Category-based priority
  if (category === 'alert') priority = Math.max(priority, 0.8);
  if (category === 'security') priority = Math.max(priority, 0.85);
  if (category === 'billing') priority = Math.max(priority, 0.6);
  if (category === 'system') priority = Math.max(priority, 0.5);

  return Math.min(priority, 1.0);
}

function estimateSentiment(subject, body) {
  const text = `${subject} ${body || ''}`.toLowerCase();

  const positive = ['great', 'success', 'completed', 'online', 'healthy', 'approved', 'thanks', 'excellent'];
  const negative = ['error', 'failed', 'down', 'critical', 'warning', 'rejected', 'breach', 'issue', 'problem'];

  const posCount = positive.filter(kw => text.includes(kw)).length;
  const negCount = negative.filter(kw => text.includes(kw)).length;

  if (negCount > posCount + 1) return 'negative';
  if (posCount > negCount + 1) return 'positive';
  return 'neutral';
}

// Process each email item
for (const item of $input.all()) {
  const msg = item.json;
  const subject = msg.subject || msg.headers?.subject || 'No Subject';
  const sender = msg.sender || msg.from || 'unknown';
  const bodyPreview = (msg.body?.plain || msg.body?.html || '').substring(0, 500);
  const messageId = msg['message-id'] || msg['Message-Id'] || `email_${Date.now()}`;

  const category = categorizeEmail(subject, sender);
  const priority = estimatePriority(category, subject);
  const sentiment = estimateSentiment(subject, bodyPreview);

  results.push({
    json: {
      ts: Math.floor(Date.now() / 1000),
      subject: subject,
      sender: sender,
      body_preview: bodyPreview.substring(0, 200),
      category: category,
      sentiment: sentiment,
      priority: priority,
      processed: 0,
      message_id: messageId,
      // BI metric fields
      bi_metric: true,
      metric_name: 'email_ingestion',
      metric_value: priority,
      metric_type: category,
      source: 'mailgun',
      tags: JSON.stringify({ sender, category, sentiment })
    }
  });
}

return results;

